// Build a Word-openable (.doc) document from the AI answer.
const aiItem = $input.first();
const aiText = aiItem.json.output?.[0]?.content?.[0]?.text
  || aiItem.json.text
  || aiItem.json.message?.content
  || '';

const body = $('Webhook').first().json.body || {};
const name = body.name || '';
const company = body.company || '';
const position = body.job || '';

function esc(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function inline(s) {
  return esc(s).replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');
}

// Lightweight markdown -> HTML conversion (headings, bold, lists, paragraphs).
const lines = String(aiText).split('\n');
let bodyHtml = '';
let inList = false;

for (const raw of lines) {
  const line = raw.trim();
  const heading = line.match(/^(#{1,6})\s+(.*)$/);
  const bullet = line.match(/^[-*]\s+(.*)$/);
  const numbered = line.match(/^\d+\.\s+(.*)$/);

  if (heading) {
    if (inList) { bodyHtml += '</ul>'; inList = false; }
    const level = heading[1].length;
    bodyHtml += '<h' + level + '>' + inline(heading[2]) + '</h' + level + '>';
  } else if (bullet || numbered) {
    if (!inList) { bodyHtml += '<ul>'; inList = true; }
    bodyHtml += '<li>' + inline((bullet || numbered)[1]) + '</li>';
  } else if (line === '') {
    if (inList) { bodyHtml += '</ul>'; inList = false; }
  } else {
    if (inList) { bodyHtml += '</ul>'; inList = false; }
    bodyHtml += '<p>' + inline(line) + '</p>';
  }
}
if (inList) { bodyHtml += '</ul>'; }

const title = 'Interview Preparation - ' + esc(position) + ' at ' + esc(company);
const doc =
  "<html xmlns:o='urn:schemas-microsoft-com:office:office' " +
  "xmlns:w='urn:schemas-microsoft-com:office:word' " +
  "xmlns='http://www.w3.org/TR/REC-html40'>" +
  "<head><meta charset='utf-8'><title>" + title + "</title>" +
  "<style>body{font-family:Calibri,Arial,sans-serif;font-size:11pt;line-height:1.4;}" +
  "h1{font-size:18pt;} h2{font-size:15pt;} h3{font-size:13pt;}</style></head>" +
  "<body><h1>" + title + "</h1>" +
  "<p><b>Candidate:</b> " + esc(name) + "</p>" +
  bodyHtml +
  "</body></html>";

const safe = (name + '_' + company + '_' + position).replace(/[^a-zA-Z0-9_-]+/g, '_');
const fileName = 'Interview_Prep_' + safe + '.doc';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(doc, 'utf8'),
  fileName,
  'application/msword',
);

return [{ json: { fileName }, binary: { data: binaryData } }];
